oxy_webhelp_navlinks = {"ms_entra_id_ctr-d30753e50044":{"topics":[{"title":"Microsoft Entra ID cross-tenant recovery configuration","shortdesc":"<p class=\"shortdesc\">Configuration requirements for Microsoft Entra ID cross-tenant recovery include         Microsoft licensing tiers, RBAC privileges, target directory environment settings, and         domain mapping configurations.<\/p>","href":"saas\/ms_entra_id_ctr_config.html","attributes":{"data-id":"ms_entra_id_ctr_config"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_ctr_config-d30753e50055","topics":[]},{"title":"Microsoft Entra ID cross-tenant recovery limitations","shortdesc":"<p class=\"shortdesc\">Cross-tenant recovery has specific limitations regarding supported object types,         unique identifier collisions, and hybrid environment configurations.<\/p>","href":"saas\/ms_entra_id_ctr_limitations.html","attributes":{"data-id":"ms_entra_id_ctr_limitations"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_ctr_limitations-d30753e50066","topics":[]},{"title":"Cross-tenant recovery for hybrid identity environments","shortdesc":"<p class=\"shortdesc\">When you perform a cross-tenant recovery in a hybrid identity environment, you must         manually re-anchor on premises Active Directory users to the target Microsoft Entra ID         tenant before <span class=\"ph\">RSC<\/span> can restore supported relationships for those hybrid         identities.<\/p>","href":"saas\/ms_entra_id_ctr_hybrid_iden_envs.html","attributes":{"data-id":"ms_entra_id_ctr_hybrid_iden_envs"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_ctr_hybrid_iden_envs-d30753e50077","topics":[]},{"title":"Performing a granular cross-tenant recovery","shortdesc":"<p class=\"shortdesc\">Recover selected objects and relationships to a new tenant.<\/p>","href":"saas\/ms_entra_id_performing_granular_ctr.html","attributes":{"data-id":"ms_entra_id_performing_granular_ctr"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_performing_granular_ctr-d30753e50091","topics":[]},{"title":"Performing a full-tenant cross-tenant recovery","shortdesc":"<p class=\"shortdesc\">Recover all protected objects and relationships in a Microsoft Entra ID domain to a         new tenant.<\/p>","href":"saas\/ms_entra_id_performing_full_ctr.html","attributes":{"data-id":"ms_entra_id_performing_full_ctr"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_performing_full_ctr-d30753e50102","topics":[]}]}};